  1	import * as React from 'react';
  2	import {
  3	  ActionGroup,
  4	  Alert,
  5	  Button,
  6	  ButtonVariant,
  7	} from '@patternfly/react-core';
  8	import { DownloadIcon } from '@patternfly/react-icons/dist/esm/icons/download-icon';
  9	import classnames from 'classnames';
 10	import { useTranslation } from 'react-i18next';
 11	
 12	import './FormFooter.scss';
 13	import { useScrollContainer } from '../../pipelines-tasks/tasks-details-pages/events/useScrollContainer';
 14	import { Shadows, useScrollShadows } from '../../hooks/useScrollShadows';
 15	import { ButtonBar } from '../../common/button-bar';
 16	
 17	export interface FormFooterProps {
 18	  handleSubmit?: () => void;
 19	  handleReset?: () => void;
 20	  handleCancel?: () => void;
 21	  handleDownload?: () => void;
 22	  sticky?: boolean;
 23	  submitLabel?: string;
 24	  resetLabel?: string;
 25	  cancelLabel?: string;
 26	  isSubmitting: boolean;
 27	  errorMessage: string;
 28	  successMessage?: string;
 29	  disableSubmit: boolean;
 30	  showAlert?: boolean;
 31	  infoTitle?: string;
 32	  infoMessage?: string;
 33	  hideSubmit?: boolean;
 34	  shadow?: boolean;
 35	}
 36	
 37	const FormFooter: React.FC<FormFooterProps> = ({
 38	  handleSubmit,
 39	  handleReset,
 40	  handleCancel,
 41	  handleDownload,
 42	  submitLabel,
 43	  resetLabel,
 44	  cancelLabel,
 45	  infoTitle,
 46	  infoMessage,
 47	  isSubmitting,
 48	  errorMessage,
 49	  successMessage,
 50	  disableSubmit,
 51	  hideSubmit = false,
 52	  showAlert,
 53	  sticky,
 54	}) => {
 55	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 56	  const [scrollContainer, footerElementRef] = useScrollContainer();
 57	  const shadowPosition = useScrollShadows(sticky ? scrollContainer : null);
 58	  return (
 59	    <div
 60	      className={classnames('ocs-form-footer', {
 61	        'ocs-form-footer__sticky': sticky,
 62	        'ocs-form-footer__shadow':
 63	          sticky &&
 64	          (shadowPosition === Shadows.both ||
 65	            shadowPosition === Shadows.bottom),
 66	      })}
 67	      data-test="form-footer"
 68	      ref={footerElementRef}
 69	    >
 70	      <ButtonBar
 71	        inProgress={isSubmitting}
 72	        errorMessage={errorMessage}
 73	        successMessage={successMessage}
 74	      >
 75	        {showAlert && (
 76	          <Alert
 77	            isInline
 78	            className="co-alert"
 79	            variant="info"
 80	            title={infoTitle || t('You made changes to this page.')}
 81	          >
 82	            {infoMessage ||
 83	              t(
 84	                'Click {{submit}} to save changes or {{reset}} to cancel changes.',
 85	                {
 86	                  submit: submitLabel,
 87	                  reset: resetLabel,
 88	                },
 89	              )}
 90	          </Alert>
 91	        )}
 92	        <ActionGroup className="pf-v6-c-form pf-v6-c-form__group--no-top-margin pf-v6-u-mt-0">
 93	          {!hideSubmit && (
 94	            <Button
 95	              type={handleSubmit ? 'button' : 'submit'}
 96	              {...(handleSubmit && { onClick: handleSubmit })}
 97	              variant={ButtonVariant.primary}
 98	              isDisabled={disableSubmit}
 99	              data-test-id="submit-button"
100	              data-test="save-changes"
101	            >
102	              {submitLabel || t('Save')}
103	            </Button>
104	          )}
105	          {handleReset && (
106	            <Button
107	              type="button"
108	              data-test-id="reset-button"
109	              variant={ButtonVariant.secondary}
110	              onClick={handleReset}
111	            >
112	              {resetLabel || t('Reload')}
113	            </Button>
114	          )}
115	          {handleCancel && (
116	            <Button
117	              type="button"
118	              data-test-id="cancel-button"
119	              variant={ButtonVariant.secondary}
120	              onClick={handleCancel}
121	            >
122	              {cancelLabel || t('Cancel')}
123	            </Button>
124	          )}
125	          {handleDownload && (
126	            <Button
127	              type="button"
128	              data-test-id="download-button"
129	              variant={ButtonVariant.secondary}
130	              className="pf-v6-c-button--align-right hidden-sm hidden-xs"
131	              onClick={handleDownload}
132	              icon={<DownloadIcon />}
133	            >
134	              {t('Download')}
135	            </Button>
136	          )}
137	        </ActionGroup>
138	      </ButtonBar>
139	    </div>
140	  );
141	};
142	export default FormFooter;

